import{_ as e,o as a,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Common Sources of SAN Reporting Discrepancies","description":"","frontmatter":{"title":"Common Sources of SAN Reporting Discrepancies","slug":"common-sources-of-san-reporting-discrepancies"},"headers":[],"relativePath":"marketer-hub/common-sources-of-san-reporting-discrepancies.md","filePath":"marketer-hub/common-sources-of-san-reporting-discrepancies.md"}'),s={name:"marketer-hub/common-sources-of-san-reporting-discrepancies.md"};function n(i,t,d,l,c,h){return a(),o("div",null,[...t[0]||(t[0]=[r('<p>The following Branch Universal Ad Partners are <a href="./what-is-a-self-attributing-network.html">Self Attributing Networks</a>:</p><ul><li><strong>Apple Ads</strong></li><li><strong>Facebook Ads</strong></li><li><strong>Google Ads</strong></li><li><strong>Google Marketing Platform</strong></li><li><strong>Snap</strong></li><li><strong>Twitter Ads</strong></li></ul><h2 id="common-sources-of-reporting-discrepancies" tabindex="-1">Common Sources of Reporting Discrepancies <a class="header-anchor" href="#common-sources-of-reporting-discrepancies" aria-label="Permalink to &quot;Common Sources of Reporting Discrepancies&quot;">​</a></h2><h3 id="available-reporting-filters" tabindex="-1">Available Reporting Filters <a class="header-anchor" href="#available-reporting-filters" aria-label="Permalink to &quot;Available Reporting Filters&quot;">​</a></h3><p>Self-Attributing Networks (SANs) do not always support all of the dimensions available in your Branch analytics. Please refer to the following table when using Compare by dimensions.</p><table tabindex="0"><thead><tr><th></th><th><strong>Facebook</strong></th><th><strong>Google</strong></th><th><strong>Apple Ads</strong></th><th><strong>Snap</strong></th></tr></thead><tbody><tr><td><strong>Feature</strong></td><td>Supported</td><td>Supported</td><td>Supported</td><td>Supported</td></tr><tr><td><strong>Channel</strong></td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td></tr><tr><td><strong>Campaign</strong></td><td>Supported</td><td>Supported</td><td>Supported</td><td>Supported</td></tr><tr><td><strong>Tags</strong></td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td></tr><tr><td><strong>Stage</strong></td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td></tr><tr><td><strong>Ad Partner</strong></td><td>Supported</td><td>Supported</td><td>Supported</td><td>Supported</td></tr><tr><td><strong>Secondary Publisher</strong></td><td>Supported</td><td>Supported</td><td>Unsupported</td><td>Unsupported</td></tr><tr><td><strong>Ad Set Name</strong></td><td>Supported</td><td>Unsupported</td><td>Supported</td><td>Supported</td></tr><tr><td><strong>Ad Name</strong></td><td>Supported</td><td>Unsupported</td><td>Unsupported</td><td>Supported</td></tr><tr><td><strong>Creative Name</strong></td><td>Supported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td></tr><tr><td><strong>Keyword</strong></td><td>Unsupported</td><td>Supported</td><td>Supported</td><td>Unsupported</td></tr><tr><td><strong>Last Touch Type</strong></td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td></tr><tr><td><strong>Link ID</strong></td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td></tr><tr><td><strong>Country</strong></td><td>Supported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td></tr><tr><td><strong>OS</strong></td><td>Unsupported</td><td>Unsupported</td><td>Supported</td><td>Unsupported</td></tr><tr><td><strong>Platform</strong></td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td><td>Unsupported</td></tr></tbody></table><h3 id="timezones" tabindex="-1">Timezones <a class="header-anchor" href="#timezones" aria-label="Permalink to &quot;Timezones&quot;">​</a></h3><p>Please make sure the timezone is the same for your SAN account and your Branch account. If you are using multiple ad accounts with Branch, be sure to align the timezones of each of them.</p><p>If you are unable to align all timezones, you may notice some data on the Branch Dashboard does not line up exactly with data on the SAN Dashboard. However, data will not be lost, but merely shifted between days. Summing figures over longer periods of time should greatly diminish the effect of having inconsistent time zones.</p><p><strong>NOTE</strong>: Branch exports are in UTC so make sure that when you are comparing the information that your timezones are aligned across 1) SAN dashboard, 2) Branch dashboard and 3) any Branch exported data.</p><h3 id="limit-ad-tracking" tabindex="-1">Limit Ad Tracking <a class="header-anchor" href="#limit-ad-tracking" aria-label="Permalink to &quot;Limit Ad Tracking&quot;">​</a></h3><p>In iOS 10, Apple broke the ability for app developers to collect the IDFA if the user had enabled Limit Ad Tracking.</p><p>In this case, Branch and SANs cannot compare notes to see who drove the install. This will account for about 15% discrepancy in counts across both platforms, where Branch&#39;s tracked installs will be lower.</p><h3 id="attribution-windows" tabindex="-1">Attribution Windows <a class="header-anchor" href="#attribution-windows" aria-label="Permalink to &quot;Attribution Windows&quot;">​</a></h3><p>If one of your attribution windows on the Branch dashboard is different than the corresponding window on the SAN dashboard, the data between the two will not align. You can mitigate this by changing one of more of your attribution windows on the Branch dashboard, or changing the attribution windows in your SAN dashboard for the given ad account.</p><h3 id="last-click-attribution" tabindex="-1">Last-click Attribution <a class="header-anchor" href="#last-click-attribution" aria-label="Permalink to &quot;Last-click Attribution&quot;">​</a></h3><p>Branch&#39;s last-click attribution model can lead to differences in install counts for Branch vs self-attributing networks (SANs) that in turn cause differences in CPI metrics. Verify whether your cost and install metrics match the Ad Partner&#39;s dashboard.</p><p>If there is an install discrepancy, it is likely legitimate and due to differences in install counts, where Branch&#39;s number is more accurate. If the discrepancy is very large, investigate causes of install discrepancies through the usual troubleshooting steps.</p><h3 id="reinstalls" tabindex="-1">Reinstalls <a class="header-anchor" href="#reinstalls" aria-label="Permalink to &quot;Reinstalls&quot;">​</a></h3><p>Apple Ads&#39; dashboard shows reinstalls as conversions in its default view, but Branch calls these installs &quot;REINSTALLS.&quot; In the Apple dashboard, select New Downloads or Redownloads in the column selector to align data.</p><p>We remember the history of a particular user via their IDFA or Google Advertising ID (in addition to using a few other methods) and will detect whether the user is actually a new user or a returning user who had previously uninstalled your app. Facebook has a different mechanism that is limited to 180 days. Branch in some cases has detected reinstalls that occurred more than a year later.</p><h3 id="opens-vs-installs" tabindex="-1">Opens vs Installs <a class="header-anchor" href="#opens-vs-installs" aria-label="Permalink to &quot;Opens vs Installs&quot;">​</a></h3><p>Branch considers the first open to be the install. Apple Ads considers the time that the user downloaded the app to be an install. This can cause discrepancies in counts and date of install.</p><h3 id="reporting-based-on-install-date-vs-touch-date" tabindex="-1">Reporting based on Install Date vs Touch Date <a class="header-anchor" href="#reporting-based-on-install-date-vs-touch-date" aria-label="Permalink to &quot;Reporting based on Install Date vs Touch Date&quot;">​</a></h3><p>Twitter will claim and report all conversions they have tracked clicks or views for within window. Because Branch will attribute to the last partner to interact with the user, you may see up to 10-30% discrepancies.</p><h3 id="clicks-vs-link-clicks" tabindex="-1">Clicks vs Link Clicks <a class="header-anchor" href="#clicks-vs-link-clicks" aria-label="Permalink to &quot;Clicks vs Link Clicks&quot;">​</a></h3><p>Branch will only show impressions and clicks for campaigns that have installs, reinstalls, or opens. If you have campaigns that have not resulted in these app-based outcomes, we will hide them.</p><p>Please be aware that Branch receives Link Clicks from Facebook via API. This click count differs from the click count found in Facebook which includes other sources of clicks.</p><h3 id="api-latencies" tabindex="-1">API Latencies <a class="header-anchor" href="#api-latencies" aria-label="Permalink to &quot;API Latencies&quot;">​</a></h3><p>Apple Ads Attribution API can be slow to respond. Although customers can edit the timeout, the default Branch timeout in the code above is just over 1 second. If Apple Ads responds after this timeout, Branch will not attribute the install to Apple Ads.</p><h3 id="cost-data-not-matching" tabindex="-1">Cost Data Not Matching <a class="header-anchor" href="#cost-data-not-matching" aria-label="Permalink to &quot;Cost Data Not Matching&quot;">​</a></h3><p>Please ensure that you&#39;ve selected the same time zone in your Ad Partner&#39;s dashboard and your Branch dashboard.</p><h3 id="cpi-metric-not-matching" tabindex="-1">CPI Metric Not Matching <a class="header-anchor" href="#cpi-metric-not-matching" aria-label="Permalink to &quot;CPI Metric Not Matching&quot;">​</a></h3><p>Branch&#39;s last-click attribution model can lead to differences in install counts for Branch vs self-attributing networks (SANs) that in turn cause differences in CPI metrics. Verify whether your cost and install metrics match the Ad Partner&#39;s dashboard. If there is an install discrepancy, it is likely legitimate and due to differences in install counts, where Branch&#39;s number is more accurate. If the discrepancy is very large, investigate causes of install discrepancies through the usual troubleshooting steps.</p><h3 id="cost-click-and-impression-data-missing" tabindex="-1">Cost, Click and Impression Data Missing <a class="header-anchor" href="#cost-click-and-impression-data-missing" aria-label="Permalink to &quot;Cost, Click and Impression Data Missing&quot;">​</a></h3><p>Generally, re-authenticating a partner and waiting 24 hours will re-enable cost data.</p><p>When you re-authenticate, double check that you have selected the correct accounts. We will only pull cost data for accounts that you select as part of the authentication process.</p><p>Background:</p><p>Cost, click and impression data for SANs are generally sourced from Partner APIs (unless Branch impression pixels or links are being intentionally used for attribution, for example, in web campaigns). When you enable a SAN, you authenticate with your provider. Branch uses this authentication to retrieve click, cost and impression data. If the authentication token expires (for example, if you reset your password, or the partner force resets your token), then you may not see click, impression or cost data. In this case, simply re-authenticate and that will refresh your token.</p><h3 id="cost-data-missing-or-incorrect-using-compare-by-filters" tabindex="-1">Cost Data Missing or Incorrect Using &quot;Compare By&quot; Filters <a class="header-anchor" href="#cost-data-missing-or-incorrect-using-compare-by-filters" aria-label="Permalink to &quot;Cost Data Missing or Incorrect Using &quot;Compare By&quot; Filters&quot;">​</a></h3><p>Downstream events, such as <em>installs</em>, should always have the full range of compare by options in the dashboard. However, <em>clicks, impressions and cost</em> data for SAN are often imported via Partner APIs. These APIs do not necessarily provide the same breakdowns for cost data that Branch supports with raw install events, so there may be cases where the Branch Dashboard cannot compare by the same dimensions for cost data vs install data.</p><h3 id="google-ads-conversion-modeling" tabindex="-1">Google Ads Conversion Modeling <a class="header-anchor" href="#google-ads-conversion-modeling" aria-label="Permalink to &quot;Google Ads Conversion Modeling&quot;">​</a></h3><p>Google Ads uses <a href="https://support.google.com/google-ads/answer/12443859?hl=en" target="_blank" rel="noreferrer">conversion modeling</a> to estimate conversions that it cannot directly observe. These modeled conversions are included in Google Ads reporting by default.</p><p>Branch does not incorporate Google&#39;s modeled conversions. Branch reports on conversions where a match can be made between a click/impression and an app event, using methods such as deterministic matching, <a href="https://help.branch.io/marketer-hub/docs/predictive-modeling" target="_blank" rel="noreferrer">PREM</a>, or <a href="https://help.branch.io/using-branch/docs/predictive-aggregate-measurement" target="_blank" rel="noreferrer">PAM</a>.</p><p>As a result, Google Ads will typically report higher conversion counts than Branch, particularly for iOS campaigns where ATT opt-in rates are low.</p>',45)])])}const g=e(s,[["render",n]]);export{u as __pageData,g as default};
